// STONES WATCH LIST WIDGET
// ══════════════════════════════════════════════════════════════════
function WatchListWidget(){
  const [items,setItems]=useState([]);
  const [input,setInput]=useState("");
  const [loaded,setLoaded]=useState(false);
  useEffect(()=>{loadK("ng-watchlist-v1").then(d=>{setItems(Array.isArray(d)?d:[]);setLoaded(true);});},[]);
  const persist=async next=>{setItems(next);try{await saveK("ng-watchlist-v1",next);}catch{}};
  const add=()=>{const t=input.trim();if(!t)return;persist([{id:uid(),text:t,found:false,addedAt:new Date().toISOString()},...items]);setInput("");};
  const toggle=id=>persist(items.map(x=>x.id===id?{...x,found:!x.found}:x));
  const del=id=>persist(items.filter(x=>x.id!==id));
  const active=items.filter(x=>!x.found);
  const found=items.filter(x=>x.found);
  return(
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
        <div style={{display:"flex",alignItems:"center",gap:7}}>
          <span style={{fontSize:15}}>💎</span>
          <div style={{fontFamily:"'Cormorant Garamond',Georgia,serif",fontSize:mob?16:15,fontWeight:600,color:C.ink,lineHeight:1}}>Want to Buy</div>
          {active.length>0&&<span style={{background:C.purple||"#7B5EA7",color:"#fff",borderRadius:10,padding:"1px 7px",fontSize:9,fontWeight:700}}>{active.length}</span>}
        </div>
        {found.length>0&&<span style={{fontSize:9,color:C.green,fontWeight:600}}>✓ {found.length} found</span>}
      </div>
      <div style={{display:"flex",gap:6,marginBottom:active.length>0?10:0}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")add();}}
          placeholder="Stone, origin, grade…"
          style={{flex:1,background:C.card,border:`1px solid ${C.border}`,borderRadius:6,padding:"6px 10px",fontSize:12,color:C.ink,outline:"none",fontFamily:"inherit"}}/>
        <button onClick={add} disabled={!input.trim()}
          style={{background:C.purple||"#7B5EA7",color:"#fff",border:"none",borderRadius:6,padding:"6px 12px",fontSize:12,cursor:input.trim()?"pointer":"not-allowed",opacity:input.trim()?1:.4,fontFamily:"inherit",fontWeight:600}}>+</button>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:5}}>
        {active.map(x=>(
          <div key={x.id} style={{display:"flex",alignItems:"center",gap:7,padding:"5px 6px",borderRadius:5,background:C.card}}>
            <button onClick={()=>toggle(x.id)} title="Mark found" style={{width:16,height:16,borderRadius:"50%",border:`2px solid ${C.purple||"#7B5EA7"}`,background:"transparent",cursor:"pointer",flexShrink:0,padding:0}}/>
            <span style={{flex:1,fontSize:12,color:C.ink,lineHeight:1.3}}>{x.text}</span>
            <button onClick={()=>del(x.id)} style={{background:"none",border:"none",cursor:"pointer",color:C.inkFaint,fontSize:13,padding:0,lineHeight:1,flexShrink:0}}>&times;</button>
          </div>
        ))}
        {loaded&&active.length===0&&<div style={{fontSize:11,color:C.inkFaint,textAlign:"center",paddingTop:4}}>Nothing on the list yet</div>}
        {found.length>0&&(
          <div style={{marginTop:6,paddingTop:6,borderTop:`1px solid ${C.border}`}}>
            <div style={{fontSize:9,color:C.inkFaint,textTransform:"uppercase",letterSpacing:.7,marginBottom:5}}>Found</div>
            {found.map(x=>(
              <div key={x.id} style={{display:"flex",alignItems:"center",gap:7,padding:"4px 6px",borderRadius:5,opacity:.55}}>
                <button onClick={()=>toggle(x.id)} style={{width:16,height:16,borderRadius:"50%",border:"none",background:C.green,cursor:"pointer",flexShrink:0,padding:0,display:"flex",alignItems:"center",justifyContent:"center"}}>
                  <span style={{color:"#fff",fontSize:9,fontWeight:700,lineHeight:1}}>✓</span>
                </button>
                <span style={{flex:1,fontSize:11,color:C.inkFaint,textDecoration:"line-through"}}>{x.text}</span>
                <button onClick={()=>del(x.id)} style={{background:"none",border:"none",cursor:"pointer",color:C.inkFaint,fontSize:12,padding:0,lineHeight:1,flexShrink:0}}>&times;</button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// TODO WIDGET
// ══════════════════════════════════════════════════════════════════
function TodoWidget({todoKey="ng-todos-v1",isAdmin=true,allUsers=[],currentUser=null}){
  const t=useT();
  const [todos,setTodos]=useState([]);
  const [input,setInput]=useState("");
  const [loaded,setLoaded]=useState(false);
  const [dueDate,setDueDate]=useState("");
  const [recurring,setRecurring]=useState("");
  const [showDone,setShowDone]=useState(false);
  const [assignOpen,setAssignOpen]=useState(false);
  const [assignText,setAssignText]=useState("");
  const [assignDue,setAssignDue]=useState("");
  const [assignTargetId,setAssignTargetId]=useState("");

  useEffect(()=>{
    loadK(todoKey).then(data=>{
      setTodos(Array.isArray(data)?data:[]);
      setLoaded(true);
    });
  },[todoKey]);

  const persist=async(next)=>{
    setTodos(next);
    try{await saveK(todoKey,next);}catch{}
  };

  // Compute next due date for recurring tasks
  const nextRecurDue=(dueStr,freq)=>{
    const base=dueStr?new Date(dueStr+"T00:00:00"):new Date();
    // If past due, advance from today instead
    const from=base<new Date()?new Date():base;
    const d=new Date(from);
    if(freq==="daily")d.setDate(d.getDate()+1);
    else if(freq==="weekly")d.setDate(d.getDate()+7);
    else if(freq==="monthly")d.setMonth(d.getMonth()+1);
    else if(freq==="yearly")d.setFullYear(d.getFullYear()+1);
    return d.toISOString().slice(0,10);
  };

  const RECUR_LABELS={daily:"Daily",weekly:"Weekly",monthly:"Monthly",yearly:"Yearly"};

  const addTodo=()=>{
    const text=input.trim();
    if(!text)return;
    const next=[{id:uid(),text,done:false,dueDate:dueDate||"",recurring:recurring||"",createdAt:new Date().toISOString()},...todos];
    persist(next);
    setInput("");setDueDate("");setRecurring("");
  };

  const toggleDone=(id)=>{
    const t=todos.find(x=>x.id===id);
    if(!t)return;
    if(t.recurring){
      persist(todos.map(x=>x.id===id?{...x,done:false,dueDate:nextRecurDue(x.dueDate,x.recurring)}:x));
    }else{
      const newDone=!t.done;
      persist(todos.map(x=>x.id===id?{...x,done:newDone,doneAt:newDone?new Date().toISOString():undefined}:x));
    }
  };

  const deleteTodo=(id)=>persist(todos.filter(todo=>todo.id!==id));
  const setTodoDueDate=(id,date)=>persist(todos.map(todo=>todo.id===id?{...todo,dueDate:date}:todo));
  const setTodoRecurring=(id,freq)=>persist(todos.map(todo=>todo.id===id?{...todo,recurring:freq}:todo));

  // Build assignee list: admin slot + all staff users, minus self
  const adminEntry={id:"__admin__",name:"Admin (Nikhil)",key:"ng-todos-v1"};
  const assignees=[
    adminEntry,
    ...allUsers.map(u=>({id:u.id,name:u.name,key:TODO_KEY_FOR(u.email)})),
  ].filter(a=>a.key!==todoKey); // exclude self

  const doAssign=async()=>{
    const text=assignText.trim();
    if(!text||!assignTargetId)return;
    const target=assignees.find(a=>a.id===assignTargetId);
    if(!target)return;
    const existing=await loadK(target.key)||[];
    const arr=Array.isArray(existing)?existing:[];
    const next=[{id:uid(),text,done:false,dueDate:assignDue||"",assignedBy:currentUser?.name||"Admin",createdAt:new Date().toISOString()},...arr];
    await saveK(target.key,next);
    setAssignText("");setAssignDue("");setAssignOpen(false);
  };

  const pending=todos.filter(todo=>!todo.done).length;
  const doneCount=todos.filter(todo=>todo.done).length;

  const sortFn=(a,b)=>{
    if(!a.dueDate&&!b.dueDate)return 0;
    if(!a.dueDate)return 1;
    if(!b.dueDate)return -1;
    return a.dueDate.localeCompare(b.dueDate);
  };
  const activeTodos=[...todos].filter(todo=>!todo.done).sort(sortFn);
  const doneTodos=[...todos].filter(todo=>todo.done).sort(sortFn);

  const todayStr=today();
  const fmtDue=d=>{if(!d)return null;const diff=Math.round((new Date(d)-new Date(todayStr))/(86400000));if(diff<0)return{label:`${Math.abs(diff)}d overdue`,color:C.red};if(diff===0)return{label:"Today",color:C.amber};if(diff===1)return{label:"Tomorrow",color:C.amber};return{label:fmtDate(d),color:C.inkFaint};};

  const TodoRow=({t})=>{
    const due=fmtDue(t.dueDate);
    const [showOpts,setShowOpts]=useState(false);
    return(
      <div style={{display:"flex",alignItems:"center",gap:8,padding:"7px 9px",background:C.card,borderRadius:7,border:`1px solid ${due?.color===C.red&&!t.done?C.red:C.border}`,transition:"opacity .15s",position:"relative"}}>
        <button onClick={()=>toggleDone(t.id)}
          style={{width:17,height:17,borderRadius:t.recurring?"50%":4,border:`1.5px solid ${t.done?C.green:t.recurring?C.blue:C.border}`,background:t.done?C.green:"transparent",cursor:"pointer",flexShrink:0,padding:0,display:"flex",alignItems:"center",justifyContent:"center",transition:"all .15s"}}
          title={t.recurring?`Complete & advance to next ${t.recurring} occurrence`:""}>
          {t.done&&<span style={{color:"#fff",fontSize:10,lineHeight:1,fontWeight:700}}>&#10003;</span>}
          {!t.done&&t.recurring&&<span style={{color:C.blue,fontSize:8,lineHeight:1}}>↻</span>}
        </button>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:mob?15:13,color:t.done?C.inkFaint:C.ink,textDecoration:t.done?"line-through":"none",wordBreak:"break-word",lineHeight:1.4}}>{t.text}</div>
          <div style={{display:"flex",gap:6,flexWrap:"wrap",alignItems:"center",marginTop:1}}>
            {due&&<span style={{fontSize:10,color:due.color,fontWeight:due.color===C.red?600:400}}>{due.label}</span>}
            {t.recurring&&<span style={{fontSize:9,background:C.blueBg,color:C.blue,borderRadius:3,padding:"1px 5px",fontWeight:600}}>↻ {RECUR_LABELS[t.recurring]||t.recurring}</span>}
            {(t.assignedBy||t.assignedByAdmin)&&<span style={{fontSize:9,background:C.amberBg,color:C.amber,borderRadius:3,padding:"1px 5px",fontWeight:600}}>From {t.assignedBy||"Admin"}</span>}
          </div>
        </div>
        <button onClick={()=>setShowOpts(v=>!v)}
          style={{background:"none",border:"none",cursor:"pointer",color:C.inkFaint,fontSize:13,padding:"0 3px",flexShrink:0,lineHeight:1}}
          title="Options">⋯</button>
        {showOpts&&(
          <div style={{position:"absolute",right:28,top:0,background:C.surface,border:`1.5px solid ${C.border}`,borderRadius:7,padding:"8px 10px",zIndex:10,minWidth:170,boxShadow:"0 4px 18px rgba(0,0,0,.12)"}}>
            <div style={{fontSize:9,fontWeight:700,color:C.inkFaint,textTransform:"uppercase",letterSpacing:.6,marginBottom:6}}>Repeat</div>
            {["","daily","weekly","monthly","yearly"].map(f=>(
              <div key={f||"none"} onClick={()=>{setTodoRecurring(t.id,f);setShowOpts(false);}}
                style={{padding:"4px 6px",borderRadius:4,cursor:"pointer",fontSize:12,background:t.recurring===f?C.blueBg:"transparent",color:t.recurring===f?C.blue:C.ink,fontWeight:t.recurring===f?600:400,marginBottom:1}}>
                {f?`↻ ${RECUR_LABELS[f]}`:"✕ No repeat"}
              </div>
            ))}
            <div style={{borderTop:`1px solid ${C.border}`,marginTop:6,paddingTop:6}}>
              <input type="date" value={t.dueDate||""} onChange={e=>{setTodoDueDate(t.id,e.target.value);setShowOpts(false);}}
                style={{fontSize:11,border:`1px solid ${C.border}`,background:C.bg,color:C.ink,borderRadius:4,padding:"4px 6px",width:"100%",colorScheme:"light"}}/>
            </div>
            <button onClick={()=>{deleteTodo(t.id);setShowOpts(false);}}
              style={{marginTop:6,width:"100%",background:C.redBg,border:"none",color:C.red,borderRadius:4,padding:"4px 0",fontSize:11,cursor:"pointer",fontWeight:600}}>Delete</button>
          </div>
        )}
      </div>
    );
  };

  return(
    <div style={{background:C.surface,border:`1.5px solid ${C.border}`,borderRadius:10,padding:mob?"12px 14px":"15px 20px",marginBottom:11}}>
      {/* Assign modal */}
      {assignOpen&&(
        <div style={{position:"fixed",inset:0,background:"rgba(26,19,8,.45)",zIndex:900,display:"flex",alignItems:"center",justifyContent:"center",padding:20}} onClick={e=>{if(e.target===e.currentTarget)setAssignOpen(false);}}>
          <div style={{background:C.surface,borderRadius:12,width:"100%",maxWidth:400,boxShadow:"var(--e-modal)",overflow:"hidden"}}>
            <div style={{padding:"14px 18px",borderBottom:`1px solid ${C.border}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <div style={{fontFamily:"'Cormorant Garamond',Georgia,serif",fontSize:17,fontWeight:600}}>Assign a Task</div>
              <button onClick={()=>setAssignOpen(false)} style={{background:"none",border:"none",cursor:"pointer",fontSize:20,color:C.inkFaint}}>&times;</button>
            </div>
            <div style={{padding:"16px 18px",display:"flex",flexDirection:"column",gap:12}}>
              <div>
                <div style={{fontSize:10,fontWeight:700,color:C.inkFaint,textTransform:"uppercase",letterSpacing:.6,marginBottom:5}}>Assign to</div>
                <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                  {assignees.length===0&&<div style={{fontSize:12,color:C.inkFaint}}>No other users found</div>}
                  {assignees.map(a=>{const on=assignTargetId===a.id;return(
                    <button key={a.id} onClick={()=>setAssignTargetId(a.id)} style={{fontSize:12,padding:"5px 12px",borderRadius:6,border:`1.5px solid ${on?C.ink:C.border}`,background:on?C.ink:"transparent",color:on?"#FAF0DC":C.inkMid,cursor:"pointer",fontWeight:on?600:400,transition:"all .12s"}}>{a.name}</button>
                  );})}
                </div>
              </div>
              <div>
                <div style={{fontSize:10,fontWeight:700,color:C.inkFaint,textTransform:"uppercase",letterSpacing:.6,marginBottom:5}}>Task</div>
                <input value={assignText} onChange={e=>setAssignText(e.target.value)}
                  onKeyDown={e=>{if(e.key==="Enter")doAssign();}}
                  autoFocus placeholder="Describe the task…" style={{...FI,width:"100%",boxSizing:"border-box"}}/>
              </div>
              <div>
                <div style={{fontSize:10,fontWeight:700,color:C.inkFaint,textTransform:"uppercase",letterSpacing:.6,marginBottom:5}}>Due date (optional)</div>
                <input type="date" value={assignDue} onChange={e=>setAssignDue(e.target.value)} style={{...FI,width:"100%",boxSizing:"border-box",colorScheme:"light"}}/>
              </div>
            </div>
            <div style={{padding:"12px 18px",borderTop:`1px solid ${C.border}`,display:"flex",gap:8}}>
              <button onClick={()=>setAssignOpen(false)} style={{flex:1,background:"none",border:`1px solid ${C.border}`,borderRadius:6,padding:"9px",cursor:"pointer",fontSize:13,color:C.inkMid}}>Cancel</button>
              <button onClick={doAssign} disabled={!assignText.trim()||!assignTargetId} style={{flex:2,background:assignText.trim()&&assignTargetId?C.ink:"#ccc",border:"none",borderRadius:6,padding:"9px",cursor:assignText.trim()&&assignTargetId?"pointer":"default",fontSize:13,fontWeight:600,color:"#FAF0DC"}}>
                Assign{assignTargetId?` to ${assignees.find(a=>a.id===assignTargetId)?.name?.split(" ")[0]||""}` :""}
              </button>
            </div>
          </div>
        </div>
      )}
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12}}>
        <div style={{fontFamily:"'Cormorant Garamond',Georgia,serif",fontSize:mob?16:15,fontWeight:600,color:C.ink,lineHeight:1}}>To-Do</div>
        {pending>0&&<span style={{background:C.amber,color:"#fff",borderRadius:10,padding:"1px 8px",fontSize:9,fontWeight:700,lineHeight:1.6,flexShrink:0}}>{pending}</span>}
        <div style={{flex:1}}/>
        {assignees.length>0&&<button onClick={()=>{setAssignOpen(true);setAssignTargetId("");setAssignText("");setAssignDue("");}} style={{background:"none",border:`1px solid ${C.border}`,borderRadius:5,padding:"3px 9px",fontSize:11,cursor:"pointer",color:C.inkMid,lineHeight:1.4}}>Assign →</button>}
        {doneCount>0&&<button onClick={()=>setShowDone(v=>!v)} style={{background:"none",border:"none",cursor:"pointer",fontSize:11,color:C.inkFaint,padding:0}}>{showDone?`Hide completed`:`${doneCount} completed`}</button>}
      </div>
      <div style={{display:"flex",gap:6,marginBottom:activeTodos.length>0||showDone?10:0,flexWrap:"wrap"}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")addTodo();}}
          placeholder="Add a task..." style={{...FI,flex:"1 1 140px",boxSizing:"border-box",fontSize:mob?16:13,padding:"7px 10px"}}/>
        <input type="date" value={dueDate} onChange={e=>setDueDate(e.target.value)}
          style={{...FI,fontSize:mob?16:12,padding:"7px 8px",flex:"0 0 auto",colorScheme:"light"}}/>
        <select value={recurring} onChange={e=>setRecurring(e.target.value)}
          style={{...FI,fontSize:12,padding:"7px 8px",flex:"0 0 auto",color:recurring?C.blue:C.inkFaint}}>
          <option value="">No repeat</option>
          <option value="daily">↻ Daily</option>
          <option value="weekly">↻ Weekly</option>
          <option value="monthly">↻ Monthly</option>
          <option value="yearly">↻ Yearly</option>
        </select>
        <button onClick={addTodo} disabled={!input.trim()}
          style={{background:input.trim()?C.ink:"transparent",color:input.trim()?"#FAF0DC":C.inkFaint,border:`1.5px solid ${input.trim()?C.ink:C.border}`,borderRadius:6,width:34,height:34,cursor:input.trim()?"pointer":"default",fontSize:18,lineHeight:"34px",flexShrink:0,padding:0,transition:"all .15s",textAlign:"center"}}>+</button>
      </div>
      {!loaded&&<div style={{fontSize:11,color:C.inkFaint,paddingTop:4}}>Loading...</div>}
      {loaded&&(
        <div style={{display:"flex",flexDirection:"column",gap:4}}>
          <div style={{maxHeight:280,overflowY:"auto",display:"flex",flexDirection:"column",gap:4}}>
            {activeTodos.map(todo=><TodoRow key={todo.id} t={todo}/>)}
            {activeTodos.length===0&&!showDone&&<div style={{fontSize:11,color:C.inkFaint,textAlign:"center",padding:"6px 0"}}>No pending tasks 🎉</div>}
          </div>
          {showDone&&doneTodos.length>0&&(
            <>
              <div style={{fontSize:9,fontWeight:600,color:C.inkFaint,textTransform:"uppercase",letterSpacing:.7,margin:"6px 0 2px"}}>Completed</div>
              <div style={{maxHeight:180,overflowY:"auto",display:"flex",flexDirection:"column",gap:4,opacity:.7}}>
                {doneTodos.map(todo=><TodoRow key={todo.id} t={todo}/>)}
              </div>
            </>
          )}
        </div>
      )}
      {loaded&&todos.length===0&&<div style={{fontSize:11,color:C.inkFaint,textAlign:"center",paddingTop:4,paddingBottom:2}}>No tasks yet — add one above</div>}
    </div>
  );
}

