  const pendingVideoSaveRef=useRef(null); // {itemId} set when user saves while video still uploading
  const setFormPhotoList=(photos,extra={})=>setForm(f=>{const clean=photos.filter(Boolean);return{...f,photos:clean,photo:clean[0]||"",photographed:clean.length>0?true:!!f.photographed,...extra};});
  const addStockPhotoFiles=async files=>{
    const picked=Array.from(files||[]).filter(Boolean);
    if(!picked.length)return;
    const itemId=form.id;
    const existing=stockPhotos(form);
    const localUrls=picked.map(file=>URL.createObjectURL(file));
    setFormPhotoList([...existing,...localUrls],{_photoUploading:true});
    try{
      const uploaded=await Promise.all(picked.map(file=>uploadStockPhoto(itemId,file)));
      setForm(f=>{
        const cur=stockPhotos(f).filter(url=>!localUrls.includes(url));
        const next=[...cur,...uploaded];
        return{...f,photos:next,photo:next[0]||"",photographed:true,_photoUploading:false};
      });
    }catch(err){
      showToast("⚠ Photo upload failed: "+err.message);
      setForm(f=>{const cur=stockPhotos(f).filter(url=>!localUrls.includes(url));return{...f,photos:cur,photo:cur[0]||"",_photoUploading:false};});
    }finally{
      localUrls.forEach(url=>URL.revokeObjectURL(url));
    }
  };
  const filtered=useMemo(()=>stock.filter(s=>{
    const regionOk=(s.region||"India")===stockRegion;
    if(!regionOk)return false;
    const q=!search||[s.material||s.name,s.shape,s.productType,s.location,s.origin,s.notes].join(" ").toLowerCase().includes(search.toLowerCase());
    const sMarkets=Array.isArray(s.market)?s.market:[s.market||""];
    const stone=fsStones.size===0||fsStones.has(s.material);
    const shape=fsShapes.size===0||fsShapes.has(s.shape);
    const mkt=fsMarkets.size===0||sMarkets.some(m=>fsMarkets.has(m));
    const typ=fsTypes.size===0||fsTypes.has(s.productType);
    const unit=fsUnits.size===0||fsUnits.has(s.unit);
    const pfP=fPhoto==="Any"||(fPhoto==="Yes"&&s.photographed)||(fPhoto==="No"&&!s.photographed);
    const platP=fsPlats.size===0||[["Shopify",s.postedShopify],["Wix",s.postedWix],["Etsy",s.postedEtsy],["Ebay",s.postedEbay]].some(([p,v])=>fsPlats.has(p)&&v);
    const vendorP=fsVendors.size===0||fsVendors.has(s.vendor||"");
    const primaryQty=parseFloat(s.qty);
    const secondaryQty=parseFloat(s.qty2);
    const hasActualQty=(Number.isFinite(primaryQty)&&primaryQty>0)||(Number.isFinite(secondaryQty)&&secondaryQty>0);
    const hasBlankQty=(!s.qty||s.qty==="")&&(!s.qty2||s.qty2==="");
    const isMovementRow=!!(s.showId||s.showTag||s.returnedFromStockId||s.returnedAt||s.soldDate||s.soldFromShowId);
    const isSold=((s.qty!=null&&s.qty!==""&&+s.qty===0)&&(!s.qty2||s.qty2===""||+s.qty2===0))||(isMovementRow&&!hasActualQty);
    const hasQty=hasActualQty||(!isMovementRow&&hasBlankQty);
    const qtyP=qtyFilter==="all"||(qtyFilter==="sold"?isSold:hasQty);
    return q&&stone&&shape&&mkt&&typ&&unit&&pfP&&platP&&vendorP&&qtyP;
  }).sort((a,b)=>{
    if(sortBy==="name")return(a.material||"").localeCompare(b.material||"");
    if(sortBy==="qty-desc")return(+b.qty||0)-(+a.qty||0);
    if(sortBy==="qty-asc")return(+a.qty||0)-(+b.qty||0);
    if(sortBy==="value")return((+b.qty||0)*(+b.costPrice||0))-((+a.qty||0)*(+a.costPrice||0));
    if(sortBy==="location"){
      // Sort by box number: extract numeric part for natural sort
      const locNum=s=>{const m=(s.location||"").match(/\d+/);return m?+m[0]:99999;};
      const nd=locNum(a)-locNum(b);
      if(nd!==0)return nd;
      return(a.location||"zzz").localeCompare(b.location||"zzz");
    }
    const ts=d=>{if(!d)return null;const t=new Date(d).getTime();return isNaN(t)?null:t;};
    if(sortBy==="modified"){
      // Items with updatedAt (explicitly edited) always come first, sorted by updatedAt desc.
      // Items never edited (no updatedAt) fall to the bottom, sorted by addedDate desc there.
      const aHas=!!a.updatedAt,bHas=!!b.updatedAt;
      if(aHas&&!bHas)return -1;
      if(!aHas&&bHas)return 1;
      if(aHas&&bHas){const at=ts(a.updatedAt);const bt=ts(b.updatedAt);if(at==null&&bt==null)return 0;if(at==null)return 1;if(bt==null)return -1;return bt-at;}
      // Both unmodified — sort by addedDate desc
      const at2=ts(a.addedDate);const bt2=ts(b.addedDate);
      if(at2==null&&bt2==null)return 0;if(at2==null)return 1;if(bt2==null)return -1;
      return bt2-at2;
    }
    // Default: date (Last Added) — no-date items to bottom
    const at=ts(a.addedDate);const bt=ts(b.addedDate);
    if(at==null&&bt==null)return 0;
    if(at==null)return 1;
    if(bt==null)return -1;
    if(sortBy==="date-asc"){
      if(at!==bt)return at-bt;
      // Tiebreak by createdAt (precise timestamp) — same-day items: earlier first
      const act=ts(a.createdAt);const bct=ts(b.createdAt);
      if(act==null&&bct==null)return 0;if(act==null)return 1;if(bct==null)return -1;
      return act-bct;
    }
    if(at!==bt)return bt-at;
    // Tiebreak by createdAt — same-day items: most recently uploaded first
    const act=ts(a.createdAt);const bct=ts(b.createdAt);
    if(act==null&&bct==null)return 0;if(act==null)return 1;if(bct==null)return -1;
    return bct-act;
  }),[stock,search,fsStones,fsShapes,fsMarkets,fsTypes,fsUnits,fPhoto,fsPlats,fsVendors,sortBy,qtyFilter,stockRegion]);
