// GST mode: "cgst_sgst" = same state (MH), "igst" = diff state, "none" = international
function getGSTMode(buyer){
  if(!buyer) return "none";
  const country=(buyer.country||"").toLowerCase().trim();
  if(country!=="india") return "none";
  const state=(buyer.state||"").toLowerCase().trim();
  return(state==="maharashtra"||state==="mh")?"cgst_sgst":"igst";
}

function invRowColor(inv){
  const total=+inv.totalAmt||0;
  const paid=(inv.payments||[]).reduce((s,p)=>s+(+p.amount||0),0)+(+inv.paidAmount||0);
  const payDone=total>0&&paid>=total*0.99;
  const shipped=!!inv.goodsShipped;
  if(payDone&&shipped)return{background:"#E8F8EE",borderLeft:"3px solid #2A6845"};    // green — all done
  if(payDone&&!shipped)return{background:"#FEF3E2",borderLeft:"3px solid #B07D12"};   // orange — paid, not shipped
  if(!payDone&&shipped)return{background:"#E8F0FE",borderLeft:"3px solid #1A4A8A"};   // blue — shipped, not paid
  return{borderLeft:"3px solid transparent"};                                           // white — neither
}

function InvBulkView({queue,idx,setIdx,buyers,extractInvoice,onSave,onBack}){
  const [draft,setDraft]=useState(null);
  const [loading,setLoading]=useState(false);
  const [toast,setToast]=useState("");
  const showToast=m=>{setToast(m);setTimeout(()=>setToast(""),3000);};
  const file=queue[idx];

  useEffect(()=>{
    if(!file||draft)return;
    setLoading(true);
    new Promise(res=>{const r=new FileReader();r.onload=e=>{const url=e.target.result;res({dataUrl:url,b64:url.split(",")[1],mediaType:url.match(/:(.*?);/)[1],name:file.name});};r.readAsDataURL(file);})
      .then(fd=>extractInvoice(fd))
      .then(d=>{setDraft(d);})
      .catch(()=>showToast("Extraction failed — fill manually"))
      .finally(()=>setLoading(false));
  },[file,idx]);

  return(
    <Shell title="Invoicing" crumb={`Bulk Upload ${idx+1}/${queue.length}`} onHome={onBack} actions={<button className="bs" style={{fontSize:12}} onClick={onBack}>← Cancel Bulk</button>}>
      <Toast msg={toast}/>
      <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:18}}>
        <div style={{display:"flex",gap:5}}>
          {queue.map((_,i)=>(
            <div key={i} style={{width:28,height:6,borderRadius:3,background:i<idx?"#2A6845":i===idx?"#B07D12":"#E5E0D5"}}/>
          ))}
        </div>
        <span style={{fontSize:12,color:C.inkMid}}>{queue[idx]?.name}</span>
        {loading&&<span style={{fontSize:11,color:C.amber}}>✨ Extracting...</span>}
      </div>
      {!loading&&draft&&(
        <div>
          {draft._extractedBuyerName&&(
            <div style={{background:C.amberBg,border:`1px solid #F0C890`,borderRadius:6,padding:"9px 14px",marginBottom:14,fontSize:12}}>
              <span style={{fontWeight:600}}>Extracted buyer: </span>{draft._extractedBuyerName}
              {buyers.length>0&&<span style={{color:C.inkFaint}}> — match to a buyer below, or add them in Buyers first</span>}
            </div>
          )}
          <InvoiceForm
            draft={draft} setDraft={setDraft}
            buyers={buyers} accStock={[]} stock={[]}
            onSave={async inv=>{await onSave(inv);setDraft(null);}}
            onDelete={()=>{setDraft(null);if(idx<queue.length-1)setIdx(i=>i+1);else onBack();}}
            onPreview={()=>{}}
          />
        </div>
      )}
      {loading&&<div style={{textAlign:"center",paddingTop:60,color:C.inkFaint,fontSize:13}}>Reading invoice...</div>}
    </Shell>
  );
}

