const MISC_BILL_KEY="ng-misc-bill-counter-v1";

async function downloadMiscBill(bill){
  const co=COMPANIES[bill.company||"nikhil"]||CO;
  const shipping=+bill.shipping||0;
  const subtotal=(bill.items||[]).reduce((s,it)=>s+(+it.qty||0)*(+it.rate||0),0);
  const total=subtotal+shipping;

  const itemRows=(bill.items||[]).map((it,i)=>{
    const base=(+it.qty||0)*(+it.rate||0);
    return`<tr>
      <td style="border:1px solid #ccc;padding:6px 9px;text-align:center">${i+1}</td>
      <td style="border:1px solid #ccc;padding:6px 9px">${it.desc||"—"}</td>
      <td style="border:1px solid #ccc;padding:6px 9px;text-align:center">${it.hsn||""}</td>
      <td style="border:1px solid #ccc;padding:6px 9px;text-align:right">${it.qty} ${it.unit}</td>
      <td style="border:1px solid #ccc;padding:6px 9px;text-align:right">₹${(+it.rate||0).toLocaleString("en-IN",{minimumFractionDigits:2})}</td>
      <td style="border:1px solid #ccc;padding:6px 9px;text-align:right;font-weight:600">₹${base.toLocaleString("en-IN",{minimumFractionDigits:2})}</td>
    </tr>`;
  }).join("");

  // Helper: fetch a URL and convert to base64 data URI for reliable offline/print rendering
  const toDataUri=async url=>{
    try{const r=await fetch(url);const blob=await r.blob();return await new Promise(res=>{const fr=new FileReader();fr.onload=e=>res(e.target.result);fr.readAsDataURL(blob);});}catch{return url;}
  };

  // PAN photos — new multi-photo array; fall back to legacy single fields
  const rawPanPhotos=bill.panPhotos?.length
    ?bill.panPhotos
    :(bill.panDocUrl||bill.panDocData?[{url:bill.panDocUrl||"",data:bill.panDocData||"",name:"PAN Card"}]:[]);
  const panImgSrcs=await Promise.all(rawPanPhotos.map(async ph=>{
    let src=ph.url||ph.data||"";
    if(src&&src.startsWith("http"))src=await toDataUri(src);
    return src?{src,name:ph.name||""}:null;
  }));
  const panPhotosResolved=panImgSrcs.filter(Boolean);

  const panSection=panPhotosResolved.length
    ?`<div style="margin-top:28px;border-top:1px solid #ddd;padding-top:18px;page-break-inside:avoid">
        <div style="font-size:11px;font-weight:700;color:#666;text-transform:uppercase;letter-spacing:.6px;margin-bottom:10px">🪪 Party PAN Card</div>
        ${bill.panNumber?`<div style="font-size:12px;color:#333;margin-bottom:10px">PAN: <b style="font-family:monospace;letter-spacing:1px">${bill.panNumber}</b></div>`:""}
        <div style="display:flex;gap:16px;flex-wrap:wrap">
          ${panPhotosResolved.map((p,i)=>`<div>
            <img src="${p.src}" style="max-width:340px;max-height:220px;border:1px solid #ccc;border-radius:6px;display:block"/>
            <div style="font-size:10px;color:#888;margin-top:4px;font-weight:600;text-transform:uppercase;letter-spacing:.4px">${i===0?"Front":i===1?"Back":`Photo ${i+1}`}</div>
          </div>`).join("")}
        </div>
      </div>`
    :bill.panNumber
    ?`<div style="margin-top:18px;padding:10px 14px;background:#f8f6f0;border-radius:6px;font-size:12px">PAN: <b style="font-family:monospace;letter-spacing:1px">${bill.panNumber}</b></div>`
    :"";

  // Payment screenshot
  let payImgSrc=bill.paymentScreenshot||"";
  if(payImgSrc&&payImgSrc.startsWith("http"))payImgSrc=await toDataUri(payImgSrc);
  const paymentSection=payImgSrc
    ?`<div style="margin-top:28px;border-top:1px solid #ddd;padding-top:18px;page-break-inside:avoid">
        <div style="font-size:11px;font-weight:700;color:#666;text-transform:uppercase;letter-spacing:.6px;margin-bottom:10px">💳 Payment Screenshot</div>
        ${bill.paymentScreenshotName?`<div style="font-size:11px;color:#555;margin-bottom:8px">${bill.paymentScreenshotName}</div>`:""}
        <img src="${payImgSrc}" style="max-width:100%;max-height:500px;border:1px solid #ccc;border-radius:6px;display:block"/>
      </div>`
    :"";

  // Attached file — embed images inline; embed PDFs on a new page
  let attachSrc=bill.attachUrl||bill.attachData||"";
  if(attachSrc&&attachSrc.startsWith("http"))attachSrc=await toDataUri(attachSrc);
  const attachExt=(bill.attachExt||"").toLowerCase();
  const attachName=bill.attachName||"Attachment";
  const isAttachImg=["jpg","jpeg","png","gif","webp","bmp"].includes(attachExt)||attachSrc.startsWith("data:image");
  const attachSection=attachSrc
    ?`<div style="margin-top:28px;page-break-before:always;padding-top:18px;border-top:2px solid #1a1300">
        <div style="font-size:11px;font-weight:700;color:#666;text-transform:uppercase;letter-spacing:.6px;margin-bottom:12px">📎 Attached: ${attachName}</div>
        ${isAttachImg
          ?`<img src="${attachSrc}" style="max-width:100%;border:1px solid #ccc;border-radius:6px;display:block"/>`
          :`<embed src="${attachSrc}" type="application/pdf" style="width:100%;height:900px;border:1px solid #ccc;border-radius:6px"/>`
        }
      </div>`
    :"";

  const html=`<!DOCTYPE html><html><head><meta charset="utf-8"><title>${bill.billNumber||"Bill"}</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0}
  body{font-family:Arial,sans-serif;font-size:12px;color:#1a1300;padding:30px 36px;max-width:860px;margin:auto}
  .header{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #1a1300;padding-bottom:14px;margin-bottom:18px}
  .co-name{font-size:22px;font-weight:700;letter-spacing:-.3px;margin-bottom:4px}
  .co-info{font-size:11px;line-height:1.7;color:#444}
  .bill-title{font-size:18px;font-weight:700;text-align:right;color:#1a1300}
  .bill-meta{font-size:11px;text-align:right;color:#555;margin-top:4px;line-height:1.8}
  .supplier-box{background:#f8f6f0;border:1px solid #e0d8c8;border-radius:7px;padding:13px 16px;margin-bottom:18px;display:flex;justify-content:space-between;align-items:flex-start}
  .gst-note{display:inline-block;margin-left:8px;font-size:10px;background:#fffbea;border:1px solid #e0c060;border-radius:3px;padding:2px 7px;color:#7a5500;vertical-align:middle}
  table{width:100%;border-collapse:collapse;margin-bottom:14px}
  th{background:#f0ede4;border:1px solid #ccc;padding:7px 9px;text-align:left;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.4px}
  .totals{margin-left:auto;width:260px}
  .totals td{padding:4px 10px;font-size:12px}
  .totals .grand{font-size:15px;font-weight:700;border-top:1.5px solid #1a1300;padding-top:6px}
  .footer{margin-top:24px;font-size:10px;color:#888;border-top:1px solid #eee;padding-top:10px;display:flex;justify-content:space-between}
  @media print{body{padding:14px} @page{margin:1.2cm}}
</style></head><body>

<div class="header">
  <div>
    <div class="co-name">${co.name}</div>
    <div class="co-info">${co.address.replace(/\n/g,"<br/>")}<br/>Tel: ${co.tel} · ${co.email}<br/>GSTIN: ${co.gstin} · IEC: ${co.iec}</div>
  </div>
  <div>
    <div class="bill-title">PURCHASE BILL <span class="gst-note">GST 0% / Unregistered</span></div>
    <div class="bill-meta">
      Bill No: <b>${bill.billNumber||"—"}</b><br/>
      Date: <b>${fmtDate(bill.billDate||bill.date)}</b><br/>
      ${bill.paymentDate?`Payment Date: <b>${fmtDate(bill.paymentDate)}</b><br/>`:""}
      ${bill.paymentNote?`Ref: <b>${bill.paymentNote}</b>`:""}
    </div>
  </div>
</div>

<div class="supplier-box">
  <div>
    <div style="font-size:10px;font-weight:700;color:#666;text-transform:uppercase;letter-spacing:.5px;margin-bottom:5px">Supplier / Party</div>
    <div style="font-size:15px;font-weight:700;margin-bottom:4px">${bill.supplier||"—"}</div>
    <div style="font-size:11px;color:#666">Unregistered — No GSTIN</div>
  </div>
</div>

<table>
  <thead>
    <tr>
      <th style="width:32px">#</th>
      <th>Description</th>
      <th style="width:70px">HSN</th>
      <th style="width:90px;text-align:right">Qty</th>
      <th style="width:100px;text-align:right">Rate (₹)</th>
      <th style="width:110px;text-align:right">Amount</th>
    </tr>
  </thead>
  <tbody>${itemRows}</tbody>
</table>

<table class="totals">
  <tr><td>Subtotal (GST 0%)</td><td style="text-align:right">₹${subtotal.toLocaleString("en-IN",{minimumFractionDigits:2})}</td></tr>
  ${shipping>0?`<tr><td>Shipping</td><td style="text-align:right">₹${shipping.toLocaleString("en-IN",{minimumFractionDigits:2})}</td></tr>`:""}
  <tr class="grand"><td><b>Total</b></td><td style="text-align:right"><b>₹${total.toLocaleString("en-IN",{minimumFractionDigits:2})}</b></td></tr>
</table>

${bill.notes?`<div style="margin-top:10px;padding:10px 14px;background:#fafaf7;border-radius:6px;font-size:11px;color:#555"><b>Notes:</b> ${bill.notes}</div>`:""}

${panSection}

${paymentSection}

${attachSection}

<div class="footer" style="margin-top:24px">
  <span>Generated by ${co.name} on ${new Date().toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"})}</span>
  <span>This is a computer-generated document.</span>
</div>
</body></html>`;

  const w=window.open("","_blank");
  if(!w){alert("Please allow popups to download the bill");return;}
  w.document.write(html);
  w.document.close();
  w.focus();
  setTimeout(()=>w.print(),700);
}

